class MPSuperTokenMetrics{PLATFORM_NAME="woocommerce";CORE_MONITOR_URL="https://api.mercadopago.com/ppcore/prod/monitor/v1/event/datadog/big";MELIDATA_ERROR_EVENT_NAME="mp_checkout_error";PLUGIN_VERSION=wc_mercadopago_supertoken_bundle_params.plugin_version;PLATFORM_VERSION=wc_mercadopago_supertoken_bundle_params.platform_version;SITE_ID=wc_mercadopago_supertoken_bundle_params.site_id;CUST_ID=wc_mercadopago_supertoken_bundle_params.cust_id;LOCATION=wc_mercadopago_supertoken_bundle_params.location;SUPER_TOKEN_JS_VERSION=null;CUSTOM_CHECKOUT_STEPS={LOAD_SUPER_TOKEN:"load_super_token",SELECT_PAYMENT_METHOD:"select_payment_method",POST_SUBMIT:"post_submit"};mpSdkInstance=null;constructor(e,t){this.mpSdkInstance=e,this.SUPER_TOKEN_JS_VERSION=t}getSdkInstanceId(){try{return this?.mpSdkInstance?.getSDKInstanceId()||"Unknown"}catch(e){return"Unknown"}}getEnvironment(){return"prod"}sendMetric(e,t,r){fetch(`${this.CORE_MONITOR_URL}/${e}`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({value:`${t}`,message:`${r}`,plugin_version:this.PLUGIN_VERSION,platform:{name:this.PLATFORM_NAME,uri:window.location.href,version:this.PLATFORM_VERSION,url:`${this.LOCATION}${this.THEME?`_${this.THEME}`:""}`},details:{site_id:this.SITE_ID,environment:this.getEnvironment(),sdk_instance_id:this.getSdkInstanceId(),cust_id:this.CUST_ID,js_version:this.SUPER_TOKEN_JS_VERSION}})}).catch((e=>console.error("Super Token metrics error: ",e)))}dispatchMelidataErrorEvent(e,t){const r=e?.replace(/^\[mercado pago\]:\s*/i,"").trim()||e,s=`${t}_mercado_pago`,i=()=>{document.dispatchEvent(new CustomEvent(this.MELIDATA_ERROR_EVENT_NAME,{detail:{message:r,errorOrigin:s}}))};window.melidata||"complete"===document.readyState?i():window.addEventListener("load",(()=>i()),{once:!0})}normalizeErrorMessage(e){if(!e)return"Unknown error";const t=e?.message||("string"==typeof e?e:JSON.stringify(e));return(t?.includes("email")?"invalid_email_address_provided":t)||"Unknown error"}canUseSuperToken(e,t=null){const r=e?"":this.normalizeErrorMessage(t);this.sendMetric("can_use_super_token",e,r)}errorToAuthorizePayment(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_to_authorize_payment","true",t)}errorToGetSimplifiedAuth(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_get_simplified_auth","true",t)}errorToGetFastPaymentToken(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_get_fast_payment_token","true",t)}errorToBuildAuthenticator(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_build_authenticator","true",t)}errorToMountCVVField(e,t){const r=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.SELECT_PAYMENT_METHOD),this.sendMetric("error_to_mount_cvv_field",t?.id||"unknown",r)}errorToUpdateSecurityCode(e,t){const r=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_to_update_security_code",t?.token||"Unknown payment method token",r)}errorOnSubmit(e,t){const r=this.normalizeErrorMessage(t);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_on_submit_super_token",e,r)}errorToGetAccountPaymentMethods(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.LOAD_SUPER_TOKEN),this.sendMetric("error_to_get_account_payment_methods","true",t)}registerClickOnPlaceOrderButton(){this.sendMetric("super_token_click_on_place_order_button","true","")}registerAuthorizedPseudotoken(e,t){this.sendMetric("authorized_pseudotoken",e,"input_exists:"+(t?"true":"false"))}errorToRenderAccountPaymentMethods(e){const t=this.normalizeErrorMessage(e);this.sendMetric("error_to_render_account_payment_methods","true",t)}hasEscNotExists(e){this.sendMetric("has_esc_not_exists",e||"UNKNOWN_PAYMENT_METHOD","has_esc attribute not found in payment method")}getPaymentMethodFail(e,t){const r=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.SELECT_PAYMENT_METHOD),this.sendMetric("get_payment_method_fail",t||"UNKNOWN_PAYMENT_METHOD",r)}getPaymentMethodLoadingTime(e,t){this.sendMetric("get_payment_method_loading_time",e||"UNKNOWN_PAYMENT_METHOD",`${t}s`)}fetchPaymentMethodSuccess(e,t){this.sendMetric("fetch_payment_method_success",e||"UNKNOWN_PAYMENT_METHOD",`cvv_is_mandatory_${t}`)}fetchPaymentMethodSkipped(e,t){this.sendMetric("fetch_payment_method_skipped",e||"UNKNOWN_PAYMENT_METHOD",t)}fetchPaymentMethodTimeout(e){this.sendMetric("fetch_payment_method_timeout",e||"UNKNOWN_PAYMENT_METHOD","Fetch payment method timed out")}isNotSimplifiedAuth(){this.sendMetric("is_not_simplified_auth","true","")}cannotGetFastPaymentToken(){this.sendMetric("cannot_get_fast_payment_token","true","")}registerSelectPaymentMethod(e){const t=`super_token_${e}`;this.sendMetric("select_payment_method",t,"")}renderCreditsContract(e,t=null){const r=e?"":this.normalizeErrorMessage(t);e||this.dispatchMelidataErrorEvent(r,this.CUSTOM_CHECKOUT_STEPS.SELECT_PAYMENT_METHOD),this.sendMetric("render_credits_contract",e,r)}installmentsFilled(e){this.sendMetric("super_token_installments_filled",!0,e)}renderConsumerCreditsDetailsInnerHTML(e){e||this.dispatchMelidataErrorEvent("render_consumer_credits_details_inner_html_failed",this.CUSTOM_CHECKOUT_STEPS.SELECT_PAYMENT_METHOD),this.sendMetric("render_consumer_credits_details_inner_html",e,"")}registerOpenCreditsInfoModal(e){this.sendMetric("open_credits_info_modal","true",e)}renderConsumerCreditsDueDate(e,t=null){const r=e?"":this.normalizeErrorMessage(t);this.sendMetric("render_consumer_credits_due_date",e,r)}renderConsumerCreditsHint(e,t=null){const r=e?"":this.normalizeErrorMessage(t);this.sendMetric("render_consumer_credits_hint",e,r)}errorToUpdateCreditsContract(e){const t=this.normalizeErrorMessage(e);this.dispatchMelidataErrorEvent(t,this.CUSTOM_CHECKOUT_STEPS.SELECT_PAYMENT_METHOD),this.sendMetric("error_to_update_credits_contract","true",t)}errorToSubmitWithoutInstallmentSelected(){this.dispatchMelidataErrorEvent("no_installment_selected",this.CUSTOM_CHECKOUT_STEPS.POST_SUBMIT),this.sendMetric("error_to_submit_without_installment_selected","true","")}}